    "src/interfaces/IUSDai.sol": {
      "content": "// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import {IERC20} from "@openzeppelin/contracts/token/ERC20/IERC20.sol";

/**
 * @title USDai Interface
 * @author MetaStreet Foundation
 */
interface IUSDai is IERC20 {
    /*------------------------------------------------------------------------*/
    /* Errors */
    /*------------------------------------------------------------------------*/

    /**
     * @notice Invalid address
     */
    error InvalidAddress();

    /**
     * @notice Invalid amount
     */
    error InvalidAmount();

    /**
     * @notice Exceeded supply cap
     */
    error SupplyCapExceeded();

    /*------------------------------------------------------------------------*/
    /* Structures */
    /*------------------------------------------------------------------------*/

    /**
     * @custom:storage-location erc7201:USDai.supply
     */
    struct Supply {
        uint256 bridged;
        uint256 cap;
    }

    /*------------------------------------------------------------------------*/
    /* Events */
    /*------------------------------------------------------------------------*/

    /**
     * @notice Migrated event
     * @param description Description
     * @param data Data
     */
    event Migrated(string description, bytes data);

    /**
     * @notice Deposited event
     * @param caller Caller
     * @param recipient Recipient
     * @param depositToken Deposit token
     * @param depositAmount Deposit amount
     * @param mintAmount Mint amount
     */
    event Deposited(
        address indexed caller,
        address indexed recipient,
        address depositToken,
        uint256 depositAmount,
        uint256 mintAmount
    );

    /**
     * @notice Withdrawn event
     * @param caller Caller
     * @param recipient Recipient
     * @param withdrawToken Withdraw token
     * @param baseTokenAmount Base token amount
     * @param withdrawAmount Withdraw amount
     */
    event Withdrawn(
        address indexed caller,
        address indexed recipient,
        address withdrawToken,
        uint256 baseTokenAmount,
        uint256 withdrawAmount
    );

    /**
     * @notice Supply cap set
     * @param supplyCap Supply cap
     */
    event SupplyCapSet(uint256 supplyCap);

    /*------------------------------------------------------------------------*/
    /* Getters */
    /*------------------------------------------------------------------------*/

    /**
     * @notice Get swap adapter
     * @return Swap adapter
     */
    function swapAdapter() external view returns (address);

    /**
     * @notice Get base token
     * @return Base token
     */
    function baseToken() external view returns (address);

    /**
     * @notice Get bridged supply
     * @return Bridged supply
     */
    function bridgedSupply() external view returns (uint256);

    /**
     * /**
     * @notice Get supply cap
     * @return Supply cap
     */
    function supplyCap() external view returns (uint256);

    /*------------------------------------------------------------------------*/
    /* Public API */
    /*------------------------------------------------------------------------*/

    /**
     * @notice Deposit
     * @param depositToken Deposit token
     * @param depositAmount Deposit amount
     * @param usdaiAmountMinimum Minimum USDai amount
     * @param recipient Recipient
     * @return USDai amount
     */
    function deposit(
        address depositToken,
        uint256 depositAmount,
        uint256 usdaiAmountMinimum,
        address recipient
    ) external returns (uint256);

    /**
     * @notice Deposit
     * @param depositToken Deposit token
     * @param depositAmount Deposit amount
     * @param usdaiAmountMinimum Minimum USDai amount
     * @param recipient Recipient
     * @param data Data (for swap adapter)
     * @return USDai amount
     */
    function deposit(
        address depositToken,
        uint256 depositAmount,
        uint256 usdaiAmountMinimum,
        address recipient,
        bytes calldata data
    ) external returns (uint256);

    /**
     * @notice Withdraw
     * @param withdrawToken Withdraw token
     * @param usdaiAmount USDai amount
     * @param withdrawAmountMinimum Minimum withdraw amount
     * @param recipient Recipient
     * @return Withdraw amount
     */
    function withdraw(
        address withdrawToken,
        uint256 usdaiAmount,
        uint256 withdrawAmountMinimum,
        address recipient
    ) external returns (uint256);

    /**
     * @notice Withdraw
     * @param withdrawToken Withdraw token
     * @param usdaiAmount USD amount
     * @param withdrawAmountMinimum Withdraw amount minimum
     * @param recipient Recipient
     * @param data Data (for swap adapter)
     * @return Withdraw amount
     */
    function withdraw(
        address withdrawToken,
        uint256 usdaiAmount,
        uint256 withdrawAmountMinimum,
        address recipient,
        bytes calldata data
    ) external returns (uint256);

    /*------------------------------------------------------------------------*/
    /* Permissioned API */
    /*------------------------------------------------------------------------*/

    /**
     * @notice Set supply cap
     * @param cap Supply cap
     */
    function setSupplyCap(
        uint256 cap
    ) external;
}
"
    },
    "src/interfaces/ISwapAdapter.sol": {
      "content": "// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

/**
 * @title Swap Adapter Interface
 * @author MetaStreet Foundation
 */
interface ISwapAdapter {
    /*------------------------------------------------------------------------*/
    /* Events */
    /*------------------------------------------------------------------------*/

    /**
     * @notice Swapped in event
     * @param inputToken Input token
     * @param inputAmount Input amount
     * @param baseOutputAmount Base token output amount
     */
    event SwappedIn(address indexed inputToken, uint256 inputAmount, uint256 baseOutputAmount);

    /**
     * @notice Swapped out event
     * @param outputToken Output token
     * @param baseInputAmount Base token input amount
     * @param outputAmount Output amount
     */
    event SwappedOut(address indexed outputToken, uint256 baseInputAmount, uint256 outputAmount);

    /*------------------------------------------------------------------------*/
    /* Getter */
    /*------------------------------------------------------------------------*/

    /**
     * @notice Base token
     * @return Base Token
     */
    function baseToken() external view returns (address);

    /*------------------------------------------------------------------------*/
    /* Permissioned API */
    /*------------------------------------------------------------------------*/

    /**
     * @notice Swap in for base token
     * @param inputToken Input token
     * @param inputAmount Input amount
     * @param minBaseAmount Minimum base token amount
     * @param path Swap path
     * @return Base amount
     */
    function swapIn(
        address inputToken,
        uint256 inputAmount,
        uint256 minBaseAmount,
        bytes calldata path
    ) external returns (uint256);

    /**
     * @notice Swap out of base token
     * @param outputToken Output token
     * @param baseAmount Base token amount
     * @param minOutputAmount Minimum output amount
     * @param path Swap path
     * @return Output amount
     */
    function swapOut(
        address outputToken,
        uint256 baseAmount,
        uint256 minOutputAmount,
        bytes calldata path
    ) external returns (uint256);
}
"
    },
    "src/interfaces/IMintableBurnable.sol": {
      "content": "// SPDX-License-Identifier: MIT
